const gulp=require("gulp"),gutil=require("gulp-util"),{execSync:execSync}=require("child_process");function runCmd(e,t){try{execSync(t,{stdio:[0,1,2]})}catch(t){throw new gutil.PluginError({plugin:e,message:t.message})}}gulp.task("eslint",function(e){runCmd("eslint","npm run eslint-fix"),e()}),gulp.task("dev-test",gulp.series("eslint",function(e){runCmd("dev-test","npm run dev-test"),e()})),gulp.task("esdoc",gulp.series("dev-test",function(e){runCmd("esdoc","npm run esdoc"),e()})),gulp.task("webpack",gulp.series("esdoc",function(e){runCmd("webpack","npm run webpack"),e()})),gulp.task("prod-test",gulp.series("webpack",function(e){runCmd("prod-test","npm run prod-test"),e()})),gulp.task("web-test",gulp.series("prod-test",function(e){runCmd("web-test","npm run web-test"),e()})),gulp.task("build",gulp.series("web-test",function(e){gutil.log("Build is complete."),e()})),gulp.task("watch",function(e){gulp.watch(["src/**/*.js","test/**/*.js","gulpfile.js","package.json"],gulp.series("build")),e()}),gulp.task("default",gulp.series("build","watch",function(e){gutil.log("Default task is complete."),e()}));